// Obtener base de datos global del workflow
const db = $getWorkflowStaticData('global');

// Inicializar si no existe
if (!db.comentariosRespondidos) {
  db.comentariosRespondidos = [];
}

if (!db.ultimaLimpieza) {
  db.ultimaLimpieza = new Date().toISOString();
}

// Limpiar registros viejos cada 7 días
const ultimaLimpieza = new Date(db.ultimaLimpieza);
const ahora = new Date();
const diasDesdeUltimaLimpieza = (ahora - ultimaLimpieza) / (1000 * 60 * 60 * 24);

if (diasDesdeUltimaLimpieza >= 7) {
  // Mantener solo los últimos 500 comentarios
  if (db.comentariosRespondidos.length > 500) {
    db.comentariosRespondidos = db.comentariosRespondidos.slice(-500);
  }
  db.ultimaLimpieza = ahora.toISOString();
}

// Verificar cada comentario
const comentariosNuevos = [];

for (const item of $input.all()) {
  const comentarioId = item.json.id;
  const yaRespondido = db.comentariosRespondidos.includes(comentarioId);

  if (!yaRespondido) {
    comentariosNuevos.push(item.json);
  }
}

// Si no hay comentarios nuevos, retornar array vacío
if (comentariosNuevos.length === 0) {
  return [];
}

// Retornar solo los comentarios nuevos
return comentariosNuevos.map(c => ({ json: c }));

