// Obtener base de datos global
const db = $getWorkflowStaticData('global');

// Asegurarse que el array existe
if (!db.comentariosRespondidos) {
  db.comentariosRespondidos = [];
}

// Guardar el ID del comentario
const comentarioId = $input.first().json.id;
const username = $input.first().json.from?.username || 'unknown';

if (!db.comentariosRespondidos.includes(comentarioId)) {
  db.comentariosRespondidos.push(comentarioId);

  // Log para debugging
  console.log(`✅ Comentario guardado: ${comentarioId} de @${username}`);
  console.log(`📊 Total comentarios en DB: ${db.comentariosRespondidos.length}`);
}

// Retornar los datos originales
return $input.all();

